CREATE FUNCTION plpgsql_case_without_else(input_value INT4)
				RETURNS TEXT AS $$
				DECLARE
					msg TEXT;
				BEGIN
					CASE input_value
						WHEN 1 THEN
							msg := 'one';
					END CASE;
