				RETURNS INT AS $$
				DECLARE
					item_cursor CURSOR FOR
						SELECT x FROM (VALUES (1), (2), (3)) AS v(x) ORDER BY x;
					row_value INT;
					total INT := 0;
				BEGIN
					OPEN item_cursor;
					LOOP
						FETCH item_cursor INTO row_value;
						EXIT WHEN NOT FOUND;
						total := total + row_value;
					END LOOP;
					CLOSE item_cursor;
					RETURN total;
				END;
				$$ LANGUAGE plpgsql;

