						WHERE id BETWEEN min_id AND max_id
						ORDER BY id;
					row_value INT;
					total INT := 0;
				BEGIN
					OPEN item_cursor(low_id, high_id);
					LOOP
						FETCH item_cursor INTO row_value;
						EXIT WHEN NOT FOUND;
						total := total + row_value;
					END LOOP;
					CLOSE item_cursor;
					RETURN total;
