							ARRAY['a']::character(3)[] @> ARRAY['a  ']::character(3)[],
							ARRAY[1.23]::numeric(5,2)[] && ARRAY[1.23]::numeric(5,2)[];

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY['a']::character(3)[]),
							(ARRAY['a  ']::character(3)[])
						) AS v(labels);

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY['abc']::varchar(3)[]),
							(ARRAY['abc']::varchar(3)[])
						) AS v(labels);

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY[1.23]::numeric(5,2)[]),
							(ARRAY[1.23]::numeric(5,2)[])
						) AS v(labels);

SELECT count(*)
						FROM (VALUES
							(ARRAY['abc']::varchar(3)[]),
							(ARRAY['abc']::varchar(3)[])
						) AS v(labels)
						GROUP BY labels;

